#include <numeric>
#include <bits/stdc++.h>
using namespace std;
const int MOD = 1000000007;

class Solution {
public:
    int countPaths(int n, vector<vector<int>>& edges, int s, int t) {
        vector<vector<pair<int,int>>> adj(n);
        for (auto &e : edges) {
            int u = e[0], v = e[1], w = e[2];
            adj[u].push_back({v, w});
        }
        const long long INF = LLONG_MAX/4;
        vector<long long> dist(n, INF);
        vector<int> ways(n, 0);
        dist[s] = 0;
        ways[s] = 1;
        using P = pair<long long,int>;
        priority_queue<P, vector<P>, greater<P>> pq;
        pq.push({0, s});
        while (!pq.empty()) {
            auto _tmp_binding_0 = pq.top(); auto d = _tmp_binding_0.first; auto u = _tmp_binding_0.second; pq.pop();
            if (d != dist[u]) continue;
            for (auto &pr : adj[u]) {
                int v = pr.first; int w = pr.second;
                long long nd = d + w;
                if (nd < dist[v]) {
                    dist[v] = nd;
                    ways[v] = ways[u];
                    pq.push({nd, v});
                } else if (nd == dist[v]) {
                    ways[v] = (ways[v] + ways[u]) % MOD;
                }
            }
        }
        return ways[t] % MOD;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n, m;
    if (!(cin >> n >> m)) return 0;
    int m_repeat; cin >> m_repeat; // ignore duplicate
    vector<vector<int>> edges;
    edges.reserve(m);
    for (int i = 0; i < m; ++i) {
        int u, v, w; cin >> u >> v >> w;
        edges.push_back({u, v, w});
    }
    int s, t; cin >> s >> t;
    Solution sol;
    int ans = sol.countPaths(n, edges, s, t);
    cout << ans << "\n";
    return 0;
}
